fn(state => {
  const { Data } = state.data;
  state.referrals = Data;
  state.interventions = [];
  return state;
});

each('$.referrals[*]',
  http.post('/primes/fetch/paging/v3/retrievedatawithpaging', {
    "ShippingProcessId": "SHP-2358",
    "PartnerId": "PNR-1363",
    "InteropID": "INT-1436",
    "APIVersion": "V3",
    "QueryParameters": [
      {
        "ParameterName": "{record_ids}",
        "Value": state => state.data.progres_lpinterventionid
      }
    ]
  }).then(state => {
    const rawData = state.data.Data;
    const lpInterventionId = state.referrals[state.index].progres_lpinterventionid;

    // Group by intervention number and aggregate
    const grouped = {};

    for (const record of rawData) {
      const key = record.progres_interventionnumber;

      if (!grouped[key]) {
        // First record - use as base
        grouped[key] = {
          ...record,
          progres_lpinterventionid: lpInterventionId,
          // Initialize aggregation arrays
          _languages: new Set(),
          _specificNeeds: []
        };
      }

      // Aggregate languages (dedupe via Set)
      const langName = record['progres_language.progres_languagecodeidname'];
      if (langName) {
        grouped[key]._languages.add(langName);
      }

      // Aggregate specific needs (category + subcategory pairs)
      const spnCategory = record['progres_specificneed.progres_spncategory2name'];
      const spnSubcategory = record['progres_specificneed.progres_spnsubcategory2name'];
      if (spnCategory) {
        const exists = grouped[key]._specificNeeds.some(
          sn => sn.category === spnCategory && sn.subcategory === spnSubcategory
        );
        if (!exists) {
          grouped[key]._specificNeeds.push({
            category: spnCategory,
            subcategory: spnSubcategory,
            categoryId: record['progres_specificneed.specificneeds.progres_spncategory2'],
            subcategoryId: record['progres_specificneed.specificneeds.progres_spnsubcategory2']
          });
        }
      }
    }

    // Convert to array and finalize
    const dedupedData = Object.values(grouped).map(record => {
      record._languages = Array.from(record._languages);
      return record;
    });

    console.log(`SHP-2358 returned ${rawData.length} records, deduplicated to ${dedupedData.length}`);

    state.interventions.push(...dedupedData);
    return state;
  })
);

Send-Decision-to-Ping.body:
fn(state => {
  const statusMap = {
    'acknowledged': '125080003',
    'rejected': '125080004'
  };

  const decisions = state.decision
    .filter(d => {
      if (d.status === 'pending') {
        console.log(`Skipping decision for ${d.progres_interventionnumber}: status is pending`);
        return false;
      }

      const parts = d.progres_interventionnumber?.split(',') || [];
      if (parts.length < 3 || !parts[1] || !parts[2]) {
        console.log(`Discarding old referral for case ${d.case_id}: progres_interventionnumber missing lpInterventionId or businessUnit. Value: "${d.progres_interventionnumber}"`);
        return false;
      }

      return true;
    })
    .map(d => {
      const [, lpInterventionId, businessUnit] = d.progres_interventionnumber.split(',');
      const currentDate = new Date().toISOString().split('T')[0];

      const reasonText = d.closure_reason && d.closure_reason !== 'No reason specified.'
        ? `: ${d.closure_reason}`
        : '';
      const comment = `Referral ${d.status} by PRIMERO${reasonText}`;

      return {
        ExternalId: d.case_id,
        Attachments: [
          {

            "Comment": comment
          }
        ],
        Fields: [
          { Name: 'progres_lpinterventionid', Value: lpInterventionId },
          { Name: 'progres_businessunit', Value: businessUnit },
          { Name: 'progres_primerotransferstatus', Value: statusMap[d.status] || '125080001' },
          { Name: 'progres_primerotransferstatusdate', Value: currentDate },
          { Name: 'progres_primeroid', Value: d.case_id },
          { Name: 'progres_primerocaseworker', Value: d.primero_user },
       //   { Name: 'progres_comments_displayfield', Value: comment }
        ]
      };
    });

  state.pingPayload = {
    ShippingProcessId: 'SHP-2748',
    InteropId: 'INT-1436',
    Data: decisions
  };

  state.hasDecisionsToSend = decisions.length > 0;

  if (state.hasDecisionsToSend) {
    console.log('Decisions to send:', JSON.stringify(state.pingPayload, null, 2));
  } else {
    console.log('No valid decisions to send to PING - skipping POST');
  }

  return state;
});

fn(state => {
  if (!state.hasDecisionsToSend) return state;

  return http.post('/api/ingestion/v2/PNR-1363/data', state.pingPayload)(state);
});

