function repairAndParseOuter(dataStr) {
  // Replace:  "Data": "{ ... }"
  // With:     "Data": "{\"...\"}"
  const repaired = dataStr.replace(
    /"Data"\s*:\s*"\{([\s\S]*?)\}"\s*,/g,
    (match, inner) => {
      // Escape any unescaped quotes inside the inner JSON object
      const fixedInner = inner.replace(/"/g, '\\"');
      return `"Data":"{${fixedInner}}",`;
    }
  );

  return JSON.parse(repaired);
}

function parseInnerDataField(obj) {
  if (!Array.isArray(obj)) return obj;

  return obj.map(item => {
    if (typeof item.Data === "string" && item.Data.trim().startsWith("{")) {
      try {
        item.Data = JSON.parse(item.Data);
      } catch {
        // leave as string if it still fails
      }
    }
    return item;
  });
}

each('$.sphTransactionIds[*]', http.post('/primes/ingestion/checkstatus/v1/pingdata', {
  "ShippingProcessId": "SHP-2731",
  "InteropID": "INT-1436",
  "PartnerId": "PNR-1363",
  "SPHTransactionId": $.data
}).then(state => {
  const raw = state.data.Data;

  if (!raw) {
    console.log('No Data returned for this transaction. Full response:', JSON.stringify(state.data, null, 2));
    return state;
  }

  let pretty;
  if (typeof raw === 'string') {
    const outerArr = repairAndParseOuter(raw);
    pretty = parseInnerDataField(outerArr);
  } else {
    // Already parsed (object or array)
    pretty = Array.isArray(raw) ? parseInnerDataField(raw) : raw;
  }

  console.log(JSON.stringify(pretty, null, 2));
  return state;
}))

