const findReferral = (referrals, service_id) => {
  const referral = referrals.find(
    referral => referral.service_record_id === service_id
  );
  return referral;
};

each('$.decisionPayload[*]', fn(state => {
  const { case_id, service_id, interoperability_referral_id, ...decision } = state.data;

  return getReferrals({ externalId: 'case_id', id: case_id })(state)
    .then(state => {
      const referrals = state.data;
      const referral = findReferral(referrals, service_id);

      if (!referral) {
        console.log(`No referral found for case_id ${case_id}. Skipping update.`);
        return state;
      }

      decision['id'] = referral.id;
      decision['record_id'] = referral.record_id;

      console.log(`Found referral ${referral.id} for case ${case_id}. Sending decision: ${decision.status}`);

      return updateReferral(
        {
          caseExternalId: 'case_id',   // was: externalId
          caseId: case_id,             // was: id (and was being set to the case_id)
          id: referral.id,             // was: referral_id
          data: decision,
        },
        state => {
          console.log(`Referral decision update successful for case: ${case_id}`);
          state.syncedReferralIds.push(interoperability_referral_id);
          return state;
        }
      )(state);
    })
    .catch(error => {
      console.log(`No case found for ${case_id}. Skipping this referral decision.`);
      return state;
    });
}));

Save-Status-in-Progres.body:
fn(state => {
  const failed = state.decisionPayload
    .filter(item => item.interoperability_referral_id)
    .filter(item => !state.syncedReferralIds.includes(item.interoperability_referral_id));

  if (failed.length > 0) {
    console.log(`Skipping PING status update for ${failed.length} referral(s) that failed to sync with Primero. They will be retried on the next run.`);
    failed.forEach(item =>
      console.log(`  - Skipped referral: ${item.interoperability_referral_id} (case: ${item.case_id})`)
    );
  }

  state.pingStatusPayloads = state.decisionPayload
    .filter(item => item.interoperability_referral_id)
    .filter(item => state.syncedReferralIds.includes(item.interoperability_referral_id))
    .map(item => ({
      "ExternalId": item.interoperability_referral_id,
      "Attachments": [],
      "Fields": [
        { "Name": "progres_interoperabilityreferralid", "Value": item.interoperability_referral_id },
        { "Name": "progres_interoperabilityreferralstatus", "Value": "125080003" },
        { "Name": "progres_comments", "Value": "Referral decision synced with PRIMERO via OpenFn" }
      ]
    }));

  console.log(`Preparing to mark ${state.pingStatusPayloads.length} referral(s) as Synced with PRIMERO`);
  return state;
});

http.post('/api/ingestion/v2/PNR-1363/data', state => ({
  "ShippingProcessId": "SHP-2284",
  "InteropId": "INT-1436",
  "Data": state.pingStatusPayloads
})).then(state => {
  console.log(`Status updated to Synced with PRIMERO for ${state.pingStatusPayloads.length} referral(s)`);
  return state;
}).catch(error => {
  console.log(`Failed to update PING status. Error: ${error.message}`);
  throw error;
});
